INSERT INTO hkgn.daily_meeting_action_item (
    meeting_id, title, description, assignee,
    due_date, priority, status, work_request_no
) VALUES (
    #{meetingId}, #{title}, #{description}, #{assignee},

        TO_DATE(#{dueDate}, 'YYYY-MM-DD')
        NULL
    ,
    #{priority}, #{status}, #{workRequestNo}
)
